 "passages": [
  {
   "group": 0,
   "id": "passage:p-wrong-depths",
   "summary": "Storm season on the Stilt Light: the ledger's blank line, Elias's landing, and soundings that read depths no chart allows \u2014 while the sea pulls back and the lamp gutters blue."
  },
  {
   "group": 1,
   "id": "passage:p-fair-lies",
   "summary": "Maren blames the instruments and burns the page; Elias grows quiet and watchful, and the lie keeps its own watch."
  },
  {
   "group": 2,
   "id": "passage:p-slack-tide",
   "summary": "At slack tide Maren takes Elias down to the lamp room and tells him what the light holds; he stays, and stands the watch beside her."
  },
  {
   "group": 3,
   "id": "passage:p-quiet-cargo",
   "summary": "Elias stows his instruments without a word; the lie rides between them, patient as the thing below."
  },
  {
   "group": 4,
   "id": "passage:p-kept-counsel",
   "summary": "Across the lamp room Elias nods once: whatever she chooses at dawn, she will not choose it alone."
  },
  {
   "group": 5,
   "id": "passage:p-the-offer",
   "summary": "Elias offers Maren a berth on the survey ship when it returns: a mapped route off the rock, hers if she wants it."
  },
  {
   "group": 6,
   "id": "passage:p-long-watch",
   "ending_title": "The Long Watch",
   "summary": "The bargain holds; the sea settles like a dog by a fire. The coast sleeps because Maren does not."
  },
  {
   "group": 7,
   "id": "passage:p-wide-water",
   "ending_title": "The Wide Water",
   "summary": "The Stilt Light goes dark; something follows the ship the way a storm follows heat. Maren is free, and the deep is awake."
  }
 ],
